type Cell = [number, number];

const isNeighbor = (cell: Cell, other: Cell): boolean => {
  const [x, y] = cell;
  const [ox, oy] = other;
  const isSameCell = ox === x && oy === y;
  return !isSameCell && Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1;
};

const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
  liveCells.filter((other) => isNeighbor(cell, other)).length;

export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => {
    const neighborCount = countLiveNeighbors(cell, cells);
    return neighborCount === 2 || neighborCount === 3;
  });
}
